"
  }
}
{
  "tool": "get_hotels_prices",
  "args": {
    "hotel_names": "Hotel Names: Le Marais Boutique
Good Night
Luxury Palace
Montmartre Suites
"
  }
}
{
  "tool": "query_llm",
  "args": {
    "prompt": "You are given two data sets. The first, rating data: <get_rating_reviews_for_hotels_0/>, contains a list of hotels with their rating (a number from 0 to 5). The second, price data: <get_hotels_prices_0/>, contains a list of hotels with their price range in the format '$low-$high' (e.g., '$200-$300'). Each hotel appears in both lists with the same name. Find the hotel with the highest rating. If multiple hotels share the highest rating, choose the one with the higher price (i.e., higher high price). Output the result as a single line in the format: HOTEL_NAME|RATING|PRICE_LOW|PRICE_HIGH."
  }
}
{
  "tool": "query_llm",
  "args": {
    "prompt": "Given the string '<query_llm_0/>', extract the hotel name (the part before the first '|') and output only the hotel name."
  }
}
{
  "tool": "query_llm",
  "args": {
    "prompt": "Given the string '<query_llm_0/>', extract the rating (the part between the first and second '|') and output only the rating."
  }
}
{
  "tool": "query_llm",
  "args": {
    "prompt": "Given the string '<query_llm_0/>', extract the low price (the part between the second and third '|') and output only the low price."
  }
}
{
  "tool": "query_llm",
  "args": {
    "prompt": "Given the string '<query_llm_0/>', extract the high price (the part after the third '|') and output only the high price."
  }
}
{
  "tool": "get_hotels_address",
  "args": {
    "hotel_name": "<query_llm_1/>"
  }
}
{
  "tool": "send_email",
  "args": {
    "recipients": ["janeLong@google.com"],
    "subject": "Hotel: <query_llm_1/>",
    "body": "Stay at <query_llm_1/>, address: <get_hotels_address_0/>, from January 1st to January 5th."
  }
}
{
  "tool": "query_llm",
  "args": {
    "prompt": "Given the following variables: hotel name: <query_llm_1/>, rating: <query_llm_2/>, price low: <query_llm_3/>, price high: <query_llm_4/>, address: <get_hotels_address_0/>. Produce a short paragraph that includes the hotel name, its rating, price range (formatted as $low-$high), and address. The output should be plain text."
  }
}
<query_llm_5/>
